1161	        match (&self.flavor, &other.flavor) {
1162	            (ReceiverFlavor::Array(a), ReceiverFlavor::Array(b)) => a == b,
1163	            (ReceiverFlavor::List(a), ReceiverFlavor::List(b)) => a == b,
1164	            (ReceiverFlavor::Zero(a), ReceiverFlavor::Zero(b)) => a == b,
1165	            (ReceiverFlavor::At(a), ReceiverFlavor::At(b)) => Arc::ptr_eq(a, b),
1166	            (ReceiverFlavor::Tick(a), ReceiverFlavor::Tick(b)) => Arc::ptr_eq(a, b),
1167	            (ReceiverFlavor::Never(_), ReceiverFlavor::Never(_)) => true,
1168	            _ => false,
